import ast, sys, requests

def extract_imports(path):
    tree = ast.parse(open(path).read())
    pkgs = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for a in node.names: pkgs.add(a.name.split('.')[0])
        elif isinstance(node, ast.ImportFrom):
            if node.module: pkgs.add(node.module.split('.')[0])
    return pkgs

def audit(path):
    for pkg in extract_imports(path):
        r = requests.get(f'https://pypi.org/pypi/{pkg}/json', timeout=5)
        verdict = 'EXISTS' if r.status_code == 200 else 'HALLUCINATED'
        risk = ' <- SLOPSQUATTING RISK' if r.status_code == 404 else ''
        print(f'{pkg}: {verdict}{risk}')
